const entrada = $input.first().json;
const texto = String(entrada.cenarios_gherkin || '').replace(/\r\n/g, '\n').trim();
let blocos = texto.split(/(?=^\s*(?:Cenário|Scenario):)/gmi).filter((bloco) => /^\s*(?:Cenário|Scenario):/i.test(bloco));
if (blocos.length === 0) blocos = [texto];
return blocos.map((bloco, indice) => ({
  json: {
    sistema_url: entrada.sistema_url,
    execution_id: `diagnostico-${$execution.id}`,
    scenario_id: `DIAG-${String(indice + 1).padStart(3, '0')}`,
    cenario: bloco.trim()
  }
}));

const origem = $('Loop do Diagnóstico').item.json;
const texto = JSON.stringify($json.content || []);
const passou = texto.includes('Page Title: Example Domain');
return {
  json: {
    ...origem,
    status: passou ? 'PASSOU' : 'ERRO_AUTOMACAO',
    detalhe_mcp: $json.content || [],
    data_execucao: new Date().toISOString()
  }
};

const resultados = $input.all().map((item) => item.json);
const passou = resultados.length > 0 && resultados.every((item) => item.status === 'PASSOU');
return [{
  json: {
    status: passou ? 'PASSOU' : 'ERRO_AUTOMACAO',
    total_cenarios: resultados.length,
    cenarios_aprovados: resultados.filter((item) => item.status === 'PASSOU').length,
    mensagem: passou ? 'Loop Gherkin e conexão Playwright MCP funcionando.' : 'O diagnóstico encontrou erro no loop ou no MCP.',
    resultados
  }
}];
